CREATE TABLE schema_migrations (version INTEGER PRIMARY KEY, applied_at TEXT NOT NULL);
CREATE TABLE protocols (id TEXT PRIMARY KEY, name TEXT NOT NULL, content_json TEXT NOT NULL, content_hash TEXT NOT NULL UNIQUE, created_at TEXT NOT NULL);
CREATE TABLE experiments (id TEXT PRIMARY KEY, name TEXT NOT NULL, protocol_id TEXT NOT NULL REFERENCES protocols(id), config_json TEXT NOT NULL, config_hash TEXT NOT NULL, status TEXT NOT NULL, created_at TEXT NOT NULL);
CREATE TABLE stages (id TEXT PRIMARY KEY, experiment_id TEXT NOT NULL REFERENCES experiments(id), name TEXT NOT NULL, ordinal INTEGER NOT NULL, status TEXT NOT NULL, UNIQUE(experiment_id, name));
CREATE TABLE tasks (id TEXT PRIMARY KEY, experiment_id TEXT NOT NULL REFERENCES experiments(id), stage_id TEXT NOT NULL REFERENCES stages(id), spec_json TEXT NOT NULL, spec_hash TEXT NOT NULL, status TEXT NOT NULL, artifact_path TEXT, result_hash TEXT, created_at TEXT NOT NULL, updated_at TEXT NOT NULL, UNIQUE(experiment_id, stage_id, spec_hash));
CREATE TABLE task_attempts (id INTEGER PRIMARY KEY AUTOINCREMENT, task_id TEXT NOT NULL REFERENCES tasks(id), attempt INTEGER NOT NULL, state TEXT NOT NULL, started_at TEXT, ended_at TEXT, exit_code INTEGER, detail_json TEXT NOT NULL, UNIQUE(task_id, attempt));
CREATE TABLE checkpoints (id TEXT PRIMARY KEY, experiment_id TEXT NOT NULL REFERENCES experiments(id), stage_id TEXT REFERENCES stages(id), task_id TEXT REFERENCES tasks(id), state_json TEXT NOT NULL, content_hash TEXT NOT NULL, created_at TEXT NOT NULL);
CREATE TABLE artifacts (id TEXT PRIMARY KEY, experiment_id TEXT NOT NULL REFERENCES experiments(id), task_id TEXT REFERENCES tasks(id), path TEXT NOT NULL UNIQUE, content_hash TEXT NOT NULL, status TEXT NOT NULL, metadata_json TEXT NOT NULL, created_at TEXT NOT NULL);
CREATE TABLE provenance (id TEXT PRIMARY KEY, artifact_id TEXT REFERENCES artifacts(id), task_id TEXT REFERENCES tasks(id), experiment_id TEXT REFERENCES experiments(id), parents_json TEXT NOT NULL, record_json TEXT NOT NULL, content_hash TEXT NOT NULL UNIQUE, created_at TEXT NOT NULL);
CREATE TABLE events (id INTEGER PRIMARY KEY AUTOINCREMENT, event_key TEXT UNIQUE, timestamp TEXT NOT NULL, type TEXT NOT NULL, severity TEXT NOT NULL, experiment_id TEXT, stage_id TEXT, task_id TEXT, payload_json TEXT NOT NULL);
CREATE TABLE decisions (id TEXT PRIMARY KEY, experiment_id TEXT, status TEXT NOT NULL, payload_json TEXT NOT NULL, created_at TEXT NOT NULL);
CREATE TABLE budgets (id TEXT PRIMARY KEY, experiment_id TEXT, payload_json TEXT NOT NULL, created_at TEXT NOT NULL);
